func transferDetailTitle(vm WarehouseTransferDetailVM) string {
	if vm.Transfer.ID == 0 {
		return "New Transfer"
	}
	if vm.Transfer.Reference != "" {
		return "Transfer: " + vm.Transfer.Reference
	}
	return fmt.Sprintf("Transfer #%d", vm.Transfer.ID)
}

func transferSaveAction(vm WarehouseTransferDetailVM) string {
	if vm.Transfer.ID == 0 {
		return "/inventory/transfers/save"
	}
	return fmt.Sprintf("/inventory/transfers/%d/save", vm.Transfer.ID)
}

func transferDateVal(t models.WarehouseTransfer) string {
	if t.TransferDate.IsZero() {
		return ""
	}
	return t.TransferDate.Format("2006-01-02")
}

